mapper.select:
select *
from ${tableName}


        and ${noColumn} like concat('%', #{query.keyword}, '%')


        and ${noColumn} = #{query.bizNo}


        and ${statusColumn} = #{query.status}


order by

    ${noColumn} desc
    1 desc

mapper.update:
update ${tableName}
set ${statusColumn} = #{status},
    update_by = #{username},
    update_time = sysdate()
where ${noColumn} = #{bizNo}

mapper.select:
select *
from erp_inventory_balance
where warehouse_id = #{warehouseId}
  and sku_id = #{skuId}
limit 1

mapper.insert:
insert into erp_inventory_movement(
    movement_no, warehouse_id, sku_id, movement_type, source_type, source_no,
    quantity, before_qty, after_qty, cost_price, operator_name,
    movement_time, create_by, create_time, remark
)
values(
    #{movementNo}, #{warehouseId}, #{skuId}, #{movementType}, #{sourceType}, #{sourceNo},
    #{quantity}, #{beforeQty}, #{afterQty}, #{costPrice}, #{operatorName},
    sysdate(), #{createBy}, sysdate(), #{remark}
)
